import React from 'react';
import './Portfolio.css';

function Portfolio() {
  const publications = [
    {
      citation: "Islam, M. R., Kashem, M. A., & Mia, L. (2021, November). AllerHybrid: A Hybrid System to Predict the Allergen Using K-mer and Physicochemical Properties. In 2021 5th International Conference on Electrical Engineering and Information Communication Technology (ICEEICT) (pp. 1-6). IEEE.",
      citedBy: 1
    },
    {
      citation: "Islam, M. R., Subramaniam, M., & Huang, P. C. (2024). Image-based Deep Learning for Smart Digital Twins: a Review. arXiv preprint arXiv:2401.02523.",
      citedBy: 3
    },
    {
      citation: "Islam, M. R., Anwar, R. H., Mastorakis, S., & Raza, M. T. (2024). Characterizing Encrypted Application Traffic through Cellular Radio Interface Protocol. arXiv preprint arXiv:2407.07361.",
      citedBy: 1
    },
    {
      citation: "Zhang, D., Islam, M. R., Huang, P. C., & Ho, C. H. (2024). Overcoming Autoware-Ubuntu Incompatibility in Autonomous Driving Systems-Equipped Vehicles: Lessons Learned. arXiv preprint arXiv:2410.06492.",
      citedBy: null
    }
  ];

  return (
    <section id="portfolio" style={{ padding: '50px' }}>
      <h1>My Projects</h1>
      <div>
        <h3>Project 1: Web App</h3>
        <p>Description of your first project.</p>
      </div>
      <div>
        <h3>Project 2: Mobile App</h3>
        <p>Description of your second project.</p>
      </div>

      <h2>Publications</h2>
      <div className="publications">
        {publications.map((pub, index) => (
          <div key={index} className="publication">
            <p>{pub.citation}</p>
            {pub.citedBy !== null && <p><strong>Cited by:</strong> {pub.citedBy}</p>}
          </div>
        ))}
      </div>
    </section>
  );
}

export default Portfolio;
